        (SELECT id FROM public.players WHERE team_id = 'b7a1e2c0-2026-4a00-a002-000000000002' AND name = $q$פביאן רואיס$q$),
        (SELECT id FROM public.players WHERE team_id = 'b7a1e2c0-2026-4a00-a002-000000000002' AND name = $q$ניקו וויליאמס$q$),
        (SELECT id FROM public.players WHERE team_id = 'b7a1e2c0-2026-4a00-a002-000000000002' AND name = $q$מיקל אויארסבאל$q$),
        (SELECT id FROM public.players WHERE team_id = 'b7a1e2c0-2026-4a00-a002-000000000002' AND name = $q$לאמין ימאל$q$)
