    $q${"mission":"לשלוט במשחק דרך החזקת כדור סבלנית, לדחוף את ארגנטינה עמוק ולנטרל את המעברים המהירים שלהם — ובעיקר לא לתת למסי מרחב חופשי לעבוד בו.","offensive_points":["להחזיק בכדור בסבלנות ולדחוף את ארגנטינה אחורה. ככל שהם עמוק יותר, כך פחות מרחב יש להם למעברים מהירים.","לנצל את הכנפיים באחד על אחד. לאמין ימאל וניקו וויליאמס מול המגנים שלהם זה יתרון ברור — להביא להם כדורים ולתת להם להכריע.","להיכנס לרחבה עם כמה שחקנים יחד. נגד הגנה צפופה צריך תנועה ופתאומיות — חדירות, חפיפות וכדורים נמוכים לאחור."],"defensive_points":["לשלוט במרחב סביב מסי. שחקן אחראי שלא נותן לו לקבל כדור בנוחות בין הקווים.","להיזהר מאיבוד כדור במקומות מסוכנים. כל איבוד שלנו יכול להפוך למעבר מהיר שלהם — למסור בטוח ולהשאיר כמה שחקנים מאחור בכל התקפה.","ריכוז מלא בכדורים נייחים. ארגנטינה מסוכנת מאוד בקרנות ובבעיטות חופשיות — סימון ברור לכל שחקן, בלי לאבד ריכוז."],"training_topics":["משחק פוזיציוני והחזקת כדור מול הגנה נמוכה","איזון הגנתי בזמן התקפה — כמה שחקנים נשארים מאחור למקרה של מעבר","הגנה על כדורים נייחים (קרנות ובעיטות חופשיות)"],"full_narrative":"ארגנטינה הם אלופי העולם — קבוצה ממושמעת, מנוסה וקרת רוח. הם לא ינסו לקחת מאיתנו את הכדור; להפך, הם ישמחו לתת לנו אותו, לשבת במבנה מסודר, ולחכות לרגע אחד שבו נאבד אותו כדי לצאת בברק עם מסי ואלוורס. לכן המשחק שלנו צריך להיות סבלני אבל חכם: להחזיק בכדור, להזיז את ההגנה שלהם, ולחפש את הכנפיים המהירים שלנו באחד על אחד. חשוב מאוד לא להסתכן במסירות מיותרות מאחור — כל איבוד כדור הוא הזמנה למתקפת נגד מסוכנת. ואסור לשכוח את הכדורים הנייחים: שם ארגנטינה מסוכנת במיוחד. אם נשמור על ריכוז ומשמעת לאורך כל המשחק — האיכות שלנו תכריע.","fingerprint":"1aewx0m"}$q$::jsonb, 0;
  
